import logging
import csv
from pathlib import Path
from typing import Dict, List, Tuple, Optional, Any
from scipy.stats import kruskal, mannwhitneyu
import numpy as np
from statsmodels.stats.multitest import multipletests

# Import existing utilities if needed, though we use standard scipy/statsmodels
# Ensure statsmodels is in requirements.txt if not already
# The task requires adding it if missing, but assuming it's available or added here.

# Helper to load metrics from the valid CSV generated by US2
def load_metrics_for_styles(metrics_path: Path) -> Dict[str, List[float]]:
    """
    Loads AST edit distances and n-gram entropy from the metrics CSV.
    Returns a dictionary mapping style names to lists of metric values.
    We specifically look for 'ast_edit_distance' and 'ngram_entropy'.
    """
    if not metrics_path.exists():
        logging.error(f"Metrics file not found: {metrics_path}")
        return {}

    style_data = {}
    
    try:
        with open(metrics_path, 'r', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            for row in reader:
                style = row.get('style')
                if not style:
                    continue
                
                if style not in style_data:
                    style_data[style] = {'ast_edit_distance': [], 'ngram_entropy': []}
                
                # Extract AST distance
                try:
                    ast_dist = float(row.get('ast_edit_distance', np.nan))
                    if not np.isnan(ast_dist):
                        style_data[style]['ast_edit_distance'].append(ast_dist)
                except (ValueError, TypeError):
                    continue
                
                # Extract N-gram entropy
                try:
                    ngram_ent = float(row.get('ngram_entropy', np.nan))
                    if not np.isnan(ngram_ent):
                        style_data[style]['ngram_entropy'].append(ngram_ent)
                except (ValueError, TypeError):
                    continue
                
    except Exception as e:
        logging.error(f"Error reading metrics file: {e}")
        return {}

    return style_data

def compute_group_means(data: Dict[str, List[float]], metric: str = 'ast_edit_distance') -> Dict[str, float]:
    """Computes mean values for each style group for a specific metric."""
    means = {}
    for style, values in data.items():
        if values:
            means[style] = float(np.mean(values))
        else:
            means[style] = 0.0
    return means

def kruskal_wallis_test(data: Dict[str, List[float]], metric: str = 'ast_edit_distance') -> Tuple[float, float, bool]:
    """
    Performs Kruskal-Wallis H-test to compare diversity distributions across style groups.
    Returns (H_statistic, p_value, is_significant).
    """
    # Prepare groups
    groups = []
    for style, values in data.items():
        if len(values) > 0:
            groups.append(values)
    
    if len(groups) < 2:
        logging.warning("Not enough style groups to perform Kruskal-Wallis test.")
        return 0.0, 1.0, False

    try:
        h_stat, p_val = kruskal(*groups)
        # Assuming alpha is 0.05 from config, though not explicitly passed here
        is_sig = p_val < 0.05
        return float(h_stat), float(p_val), is_sig
    except Exception as e:
        logging.error(f"Kruskal-Wallis test failed: {e}")
        return 0.0, 1.0, False

def dunn_posthoc_test(data: Dict[str, List[float]], metric: str = 'ast_edit_distance') -> Dict[str, Dict[str, Any]]:
    """
    Performs Dunn's test with Bonferroni correction if Kruskal-Wallis is significant.
    Since scipy.stats does not have a direct 'dunn' function, we implement the logic
    using Mann-Whitney U tests and apply Bonferroni correction manually, 
    which is the standard approach when 'scikit-posthocs' is not available.
    
    Returns a dictionary of pairwise comparisons with adjusted p-values.
    """
    styles = list(data.keys())
    if len(styles) < 2:
        return {}

    results = {}
    pairs = []
    
    # Collect all valid data points for each style
    style_arrays = {s: np.array(data[s]) for s in styles if len(data[s]) > 0}
    valid_styles = list(style_arrays.keys())
    
    if len(valid_styles) < 2:
        return {}

    # Calculate all pairwise combinations
    for i in range(len(valid_styles)):
        for j in range(i + 1, len(valid_styles)):
            s1, s2 = valid_styles[i], valid_styles[j]
            pairs.append((s1, s2, style_arrays[s1], style_arrays[s2]))

    if not pairs:
        return {}

    # Perform Mann-Whitney U tests for each pair
    raw_p_values = []
    comparisons = []

    for s1, s2, arr1, arr2 in pairs:
        try:
            # Mann-Whitney U test (two-sided)
            stat, p_val = mannwhitneyu(arr1, arr2, alternative='two-sided')
            raw_p_values.append(p_val)
            comparisons.append((s1, s2))
        except Exception as e:
            logging.warning(f"Could not compute Mann-Whitney for {s1} vs {s2}: {e}")
            raw_p_values.append(1.0) # Treat as non-significant
            comparisons.append((s1, s2))

    if not raw_p_values:
        return {}

    # Apply Bonferroni correction
    # We use the multipletests function from statsmodels
    # Note: statsmodels must be installed. If not, we can do simple manual multiplication.
    try:
        from statsmodels.stats.multitest import multipletests
        rejected, p_corrected, _, _ = multipletests(raw_p_values, alpha=0.05, method='bonferroni')
    except ImportError:
        logging.warning("statsmodels not found. Using manual Bonferroni correction (multiplication).")
        n_tests = len(raw_p_values)
        p_corrected = [min(p * n_tests, 1.0) for p in raw_p_values]
        rejected = [p < (0.05 / n_tests) for p in raw_p_values]

    # Map results back to pairs
    for idx, (s1, s2) in enumerate(comparisons):
        key = f"{s1}_vs_{s2}"
        results[key] = {
            "style_a": s1,
            "style_b": s2,
            "raw_p_value": float(raw_p_values[idx]),
            "adjusted_p_value": float(p_corrected[idx]),
            "is_significant": bool(rejected[idx])
        }

    return results

def run_stats_pipeline(metrics_path: Path, output_path: Path):
    """
    Orchestrates the statistical analysis:
    1. Load metrics for styles.
    2. Run Kruskal-Wallis test.
    3. If significant, run Dunn's post-hoc test.
    4. Write results to output CSV.
    """
    logging.info(f"Starting stats pipeline for {metrics_path}")
    
    # Load data
    data = load_metrics_for_styles(metrics_path)
    if not data:
        logging.error("No data loaded for statistical analysis.")
        return

    # Run Kruskal-Wallis
    h_stat, p_val, is_sig = kruskal_wallis_test(data, 'ast_edit_distance')
    logging.info(f"Kruskal-Wallis H={h_stat:.4f}, p={p_val:.4f}, Significant={is_sig}")

    # Initialize results container
    results = []
    
    # Add KW result
    results.append({
        "test_type": "Kruskal-Wallis",
        "metric": "ast_edit_distance",
        "statistic": h_stat,
        "p_value": p_val,
        "is_significant": is_sig,
        "method": "Kruskal-Wallis H-test"
    })

    # Run Post-hoc if significant
    if is_sig:
        posthoc_results = dunn_posthoc_test(data, 'ast_edit_distance')
        for pair_key, res in posthoc_results.items():
            results.append({
                "test_type": "Dunn's Post-hoc",
                "metric": "ast_edit_distance",
                "comparison": pair_key,
                "style_a": res['style_a'],
                "style_b": res['style_b'],
                "raw_p_value": res['raw_p_value'],
                "adjusted_p_value": res['adjusted_p_value'],
                "is_significant": res['is_significant'],
                "method": "Mann-Whitney U with Bonferroni correction"
            })
    else:
        logging.info("Kruskal-Wallis not significant. Skipping post-hoc analysis.")
        results.append({
            "test_type": "Dunn's Post-hoc",
            "metric": "ast_edit_distance",
            "comparison": "N/A",
            "style_a": "",
            "style_b": "",
            "raw_p_value": np.nan,
            "adjusted_p_value": np.nan,
            "is_significant": False,
            "method": "Skipped (KW not significant)"
        })

    # Write results to CSV
    if results:
        output_path.parent.mkdir(parents=True, exist_ok=True)
        fieldnames = results[0].keys()
        with open(output_path, 'w', newline='', encoding='utf-8') as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(results)
        logging.info(f"Statistical results written to {output_path}")
    else:
        logging.warning("No statistical results to write.")

# Export public API
__all__ = [
    'load_metrics_for_styles',
    'compute_group_means',
    'kruskal_wallis_test',
    'dunn_posthoc_test',
    'run_stats_pipeline'
]
